import { useState } from "react";
import axios from "axios";
// @ts-ignore
import "./styles.css";

interface WeatherData {
  name: string;
  sys: {
    country: string;
  };
  weather: {
    icon: string;
    description: string;
  }[];
  main: {
    temp: number;
    humidity: number;
    feels_like: number;
  };
  wind: {
    speed: number;
  };
}

export default function App() {
  const [city, setCity] = useState("");
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [error, setError] = useState("");

  const API_KEY = "e707cf0cf6c6b09c949bb02e32bf1c42";

  const fetchWeather = async () => {
    if (!city.trim()) {
      setError("Please enter a city");
      setWeather(null);
      return;
    }

    try {
      setError("");

      const response = await axios.get<WeatherData>(
        `https://api.openweathermap.org/data/2.5/weather?q=${city}&appid=${API_KEY}&units=metric`
      );

      setWeather(response.data);
    } catch {
      setWeather(null);
      setError("City not found");
    }
  };

  return (
    <div className="app">
      {/* Apple Music Style Background */}
      <div className="music-layer layer1"></div>
      <div className="music-layer layer2"></div>
      <div className="music-layer layer3"></div>

      <div className="container">
        <h1 className="title">Climate</h1>

        <div className="search-container">
          <input
            className="input"
            type="text"
            placeholder="Search city..."
            value={city}
            onChange={(e) => setCity(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") fetchWeather();
            }}
          />

          <button
            className="music-button"
            onClick={fetchWeather}
          >
            🔍
          </button>
        </div>

        {error && (
          <div className="error">
            {error}
          </div>
        )}

        {weather && (
          <div className="weather-card fade-up">
            <div className="weather-header">
              <h2>
                {weather.name}, {weather.sys.country}
              </h2>

              <img
                className="weather-icon"
                src={`https://openweathermap.org/img/wn/${weather.weather[0].icon}@4x.png`}
                alt="weather"
              />

              <div className="temperature">
                {Math.round(weather.main.temp)}°
              </div>

              <div className="description">
                {weather.weather[0].description}
              </div>
            </div>

            <div className="stats">
              <div className="stat-card">
                <span>💧</span>
                <h3>{weather.main.humidity}%</h3>
                <p>Humidity</p>
              </div>

              <div className="stat-card">
                <span>💨</span>
                <h3>{weather.wind.speed}</h3>
                <p>Wind</p>
              </div>

              <div className="stat-card">
                <span>🌡️</span>
                <h3>{Math.round(weather.main.feels_like)}°</h3>
                <p>Feels Like</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
